{
  "narrative": "你借着月光看向那条旧山路，路面长满青苔，两侧灌木丛生，隐约可见断枝碎石。传闻近期有凶兽在附近出没，但若谨慎通过，或许可行。",
  "world_action_candidates": [
    "仔细检查路面是否有新鲜痕迹",
    "返回村中询问老者更稳妥的路线",
    "准备火把和短刀再出发"
  ],
  "rumors": [
    "旧山路有人埋伏",
    "深更半夜山精作祟"
  ],
  "pressure": [
    "月亮很快会被云遮住"
  ],
  "safety_notes": [
    "夜间赶路务必保持警惕",
    "切勿单独深入密林"
  ]
}

{
  "narrative": "你听到路过的猎户提起，近日有支神秘商队绕过青茅山脚，似乎载着贵重货物。但传闻真假难辨，他们是否与商家城有关无人知晓。你决定继续自己的行程。",
  "world_action_candidates": [
    "沿山路出发，在岔路口留下布条标记",
    "向猎户打听商队更具体的信息"
  ],
  "rumors": [
    "神秘商队可能携带贵重货物，但来源不明",
    "商队可能与商家城有联系，但无法确认"
  ],
  "pressure": [
    "云层更厚，可能下雨影响视线",
    "商队传闻可能吸引盗匪，需保持警惕"
  ],
  "safety_notes": [
    "保持低调，不要主动接近未知商队",
    "出发前检查行囊，确保不遗漏重要物品"
  ]
}

{
  "narrative": "你身处青茅山腰，尚未踏出这片山脉。南疆和商家城仍在远方，传闻中的商队不过是山脚过客，与你的旅途无关。离出发还有准备，不可冒进。",
  "world_action_candidates": [
    "沿山路继续前行，留意岔路标记",
    "向猎户打听附近地形与安全路线"
  ],
  "rumors": [
    "有商队绕过山脚，但细节模糊",
    "南疆边界传闻有守卫盘查"
  ],
  "pressure": [
    "云层压低，可能降雨",
    "山中偶有野兽痕迹，需小心"
  ],
  "safety_notes": [
    "未抵南疆前，勿轻信商家城通路",
    "保持低调，避免引人注目"
  ]
}

{
  "narrative": "山脊上隐约有个人影，一个低阶散修正朝这边窥探。他目光闪烁，似乎并无敌意，但也绝非善意。瘴气中兽吼声又近了几分，体力流失隐隐加重。必须抉择下一步，东行或许能甩开窥视。",
  "world_action_candidates": [
    "小心靠近山脊，尝试与窥视者对话",
    "假装没有发现，暗中绕路避开"
  ],
  "rumors": [
    "据说这片区域的散修大多依附于某个小势力，但具体情况不明"
  ],
  "pressure": [
    "窥视者的存在让人不安，可能引来更多注意",
    "瘴气侵蚀持续，体力每况愈下"
  ],
  "safety_notes": [
    "避免贸然接触，保持距离观察对方意图"
  ]
}

{
  "narrative": "你提出要立刻找市场卖材料，但此地只是青茅山边缘，并无正式商市。瘴气弥漫，山脊上那个散修似乎注意到了你的动静，或许他知道附近有无交易点，但贸然询问可能暴露行踪。东行方向隐约有炊烟，或许有临时营地。",
  "world_action_candidates": [
    "向山脊上的散修喊话，询问附近有无交易点",
    "悄悄朝炊烟方向探查，寻找临时营地",
    "先找个隐蔽处恢复体力，再作打算"
  ],
  "rumors": [
    "有传言说青茅山外缘偶尔会有游商经过，但行踪不定",
    "据说东边山坳里有个散修聚集的临时营地，可以交换物资"
  ],
  "pressure": [
    "瘴气持续侵蚀，体力缓慢下降",
    "窥视者的存在让人不安，可能引来更多注意"
  ],
  "safety_notes": [
    "市场功能尚未开放，无法直接交易，需先探索获取信任",
    "保持警惕，对外人不可轻信"
  ]
}

{
  "narrative": "你仍在青茅山边缘的瘴气区，尚未进入南疆腹地。东侧炊烟方向可能有临时营地，山脊散修不时瞥向你。瘴气侵蚀体力，窥视者带来不安。",
  "world_action_candidates": [
    "朝炊烟方向潜行探查",
    "向散修喊话询问交易点"
  ],
  "rumors": [
    "据说青茅山深处有废弃猎屋"
  ],
  "pressure": [
    "瘴气持续消耗体力",
    "散修的窥视可能引来麻烦"
  ],
  "safety_notes": [
    "避免暴露行踪，谨慎选择接触对象",
    "先恢复体力再深入"
  ]
}

{
  "narrative": "你沿着青茅山出山小道前行，前方隐约可见南疆边缘的投影，但距离正式的商家城仍有数日路程。一位巡山弟子拦住你，说商家城近期戒备森严，非请勿入。",
  "world_action_candidates": [
    "向巡山弟子打听商家城的情况",
    "继续沿小道前行，寻找歇脚处",
    "绕道避开可能的巡逻"
  ],
  "rumors": [
    "听说商家城最近有宝黄天交易会，但外人难以混入",
    "青茅山深处似乎有异常灵气波动"
  ],
  "pressure": [
    "天色渐晚，山中可能有野兽或邪修出没",
    "巡山弟子似乎对你的身份有所怀疑"
  ],
  "safety_notes": [
    "未抵达商家城，无法获得正式奖励或加入势力",
    "请遵守本地引擎对路线的控制"
  ]
}

{
  "narrative": "天色渐暗，你在一棵老槐树下歇脚。远处山道上似乎有身影闪动，传闻说商家城与某个南疆势力暗中交锋，曾派高手截杀过路散修。你紧了紧行囊，留意着四周的风吹草动。",
  "world_action_candidates": [
    "寻一处隐蔽的山洞过夜",
    "点燃火把继续赶路"
  ],
  "rumors": [
    "听说南疆某个雪山洞府的古兽最近暴动，有散修趁机偷袭了商家队的后援",
    "有传言说青茅山深处藏着一尊邪异的骨棺，夜里会发出低鸣"
  ],
  "pressure": [
    "饥饿与疲惫同时袭来，体力在下降",
    "隐约感到有目光在暗处窥视，不似善类",
    "山雾渐浓，容易迷失方向或遭遇毒虫"
  ],
  "safety_notes": [
    "此处未进入商家城正式地界，不可贸然对隐藏主角动手",
    "所有关于凝冰的因果由本地引擎保护，仅能作为谣言暗示"
  ]
}

{
  "narrative": "你坐在老槐树下，饥肠辘辘，正盘算着如何赶路。远处山道上的身影已消失，但那股被窥视的感觉仍未散去。有传闻说南疆某些势力在青茅山附近设伏，专截落单修士。你想起宝黄天的传说，但那里贩卖的多是凡俗药材与低阶材料，所谓仙人材料不过是市井流言，此地也无从验证。",
  "world_action_candidates": [
    "沿山道小心前行，寻找一处干燥的岩洞过夜",
    "在附近采集一些可充饥的野果和药草",
    "折返一小段路，向青茅山脚猎户打听近况"
  ],
  "rumors": [
    "有人声称在宝黄天见过一块‘龙血石’，但更多人说是假货",
    "商家城暗中收购凡人灵材，据说与某个隐秘交易有关"
  ],
  "pressure": [
    "饥饿与疲惫交织，体力持续下降",
    "暗处似有目光锁定，隐约带着敌意"
  ],
  "safety_notes": [
    "宝黄天传闻混杂，不可轻信凡人市井中的仙家传言",
    "当前仅为凡人赶路阶段，不应涉足高于自身境界的交易"
  ]
}
